@Test
    public void testAverage() {
        assertTrue(Math.abs(FillGaps.average(0, 5) - 0) < 0.001);
        assertTrue(Math.abs(FillGaps.average(12, 6) - 2) < 0.001);
        assertTrue(Math.abs(FillGaps.average(1, 1) - 1) < 0.001);
    }

